import React from 'react';

const Dashboard = () => {
    const appointments = [
        { id: 1, doctor: 'Dr. Smith', date: '2024-07-01', time: '10:00 AM' },
        { id: 2, doctor: 'Dr. Johnson', date: '2024-07-05', time: '2:00 PM' },
    ];

    return (
        <div className="min-h-screen px-4 py-10 sm:px-10 bg-gradient-to-br from-green-100 to-blue-100 text-gray-800">
            {/* Welcome Header */}
            <div className="text-center mb-12">
                <h1 className="text-4xl font-extrabold text-green-700">Welcome to DocSpot Dashboard</h1>
                <p className="mt-2 text-gray-600 text-lg">Track your appointments and stay organized.</p>
            </div>

            {/* Summary Cards */}
            <div className="grid gap-6 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 mb-12">
                <div className="bg-white p-6 rounded-xl shadow hover:shadow-lg transition border-t-4 border-green-500 text-center">
                    <h2 className="text-lg text-gray-500 mb-1">Total Appointments</h2>
                    <p className="text-4xl font-bold text-green-700">{appointments.length}</p>
                </div>

                <div className="bg-white p-6 rounded-xl shadow hover:shadow-lg transition border-t-4 border-blue-500 text-center">
                    <h2 className="text-lg text-gray-500 mb-1">Upcoming</h2>
                    <p className="text-4xl font-bold text-blue-600">{appointments.length}</p>
                </div>

                <div className="bg-white p-6 rounded-xl shadow hover:shadow-lg transition border-t-4 border-yellow-500 text-center">
                    <h2 className="text-lg text-gray-500 mb-1">Notifications</h2>
                    <p className="text-4xl font-bold text-yellow-600">0</p>
                </div>
            </div>

            {/* Appointment List */}
            <div className="bg-white p-6 rounded-xl shadow-md">
                <h2 className="text-2xl font-semibold text-gray-800 mb-6 border-b pb-2">
                    Upcoming Appointments
                </h2>

                {appointments.length === 0 ? (
                    <p className="text-center text-gray-500">No upcoming appointments.</p>
                ) : (
                    <ul className="divide-y divide-gray-200">
                        {appointments.map((appt) => (
                            <li key={appt.id} className="py-4 flex flex-col sm:flex-row justify-between sm:items-center px-2 sm:px-4 hover:bg-green-50 rounded transition">
                                <div className="mb-2 sm:mb-0">
                                    <p className="text-lg font-medium text-gray-700">👨‍⚕️ {appt.doctor}</p>
                                    <p className="text-sm text-gray-500">
                                        📅 {appt.date} &nbsp;&nbsp; 🕒 {appt.time}
                                    </p>
                                </div>
                                <span className="inline-block bg-green-100 text-green-800 text-sm px-3 py-1 rounded-full font-medium">
                  Confirmed
                </span>
                            </li>
                        ))}
                    </ul>
                )}
            </div>
        </div>
    );
};

export default Dashboard;
